import { check } from "../src/auth/permissions";
import { Role } from "../src/models/role";

describe("Permission System", () => {
  describe("check()", () => {
    it("denies access when the role lacks the required permission flag", () => {
      // Arrange: Create a role with some permissions but missing the required 'admin' permission
      const role = new Role({
        id: "user-123",
        name: "Regular User",
        permissionFlags: ["read", "write"], // Missing 'admin' permission
      });

      // Act: Attempt to perform an action requiring 'admin' permission
      const result = check(role, "admin");

      // Assert: Access should be denied (check should return false)
      expect(result).toBe(false);
    });

    it("denies access when the role has empty permission flags", () => {
      // Arrange: Create a role with no permissions
      const role = new Role({
        id: "user-456",
        name: "No Permissions User",
        permissionFlags: [],
      });

      // Act: Attempt to perform an action requiring 'write' permission
      const result = check(role, "write");

      // Assert: Access should be denied
      expect(result).toBe(false);
    });

    it("denies access when the role does not have a specific permission among multiple", () => {
      // Arrange: Create a role with multiple permissions but missing 'delete'
      const role = new Role({
        id: "user-789",
        name: "Content Editor",
        permissionFlags: ["read", "write", "edit"],
      });

      // Act: Attempt to perform an action requiring 'delete' permission
      const result = check(role, "delete");

      // Assert: Access should be denied
      expect(result).toBe(false);
    });
  });
});
